/**
 * Custom ESLint Plugin: No Generated Models Barrel Value Import
 *
 * Disallows runtime (value) imports from the auto-generated model barrels:
 *   server/autoGeneratedHooks/<service>/models
 *   server/autoGeneratedHooks/<service>/models/index
 *
 * These barrels re-export all generated types for a service. Importing runtime
 * values from them pulls the entire barrel into the module graph, preventing
 * tree-shaking and inflating bundle size.
 *
 * Type-only imports are always allowed:
 *   import type { Foo } from '../../server/autoGeneratedHooks/questioner/models'; // OK
 *   import { type Foo } from '../../server/autoGeneratedHooks/questioner/models'; // OK
 *
 * Runtime value imports must target the specific leaf module instead:
 *   import { QuestionType } from '../../server/autoGeneratedHooks/questioner/models/questionType'; // OK
 */

/** Matches any path ending in autoGeneratedHooks/<service>/models or …/models/index */
const BARREL_PATTERN = /autoGeneratedHooks\/[^/]+\/models(?:\/index)?$/;

function isTypeOnlyImport(node) {
  if (node.importKind === 'type') return true;

  const specifiers = node.specifiers ?? [];
  if (specifiers.length === 0) return false;

  return specifiers.every((s) => s.importKind === 'type');
}

const noGeneratedModelsBarrelValueImportRule = {
  meta: {
    type: 'problem',
    docs: {
      description:
        'Disallow runtime (value) imports from generated model barrels; use specific leaf modules or type-only imports.',
      category: 'Best Practices',
      recommended: true,
    },
    schema: [],
    messages: {
      noValueImport:
        'Do not import runtime values from "{{module}}". Import from a specific leaf model module instead (e.g. …/models/questionType). Type-only imports are allowed.',
    },
  },

  create(context) {
    return {
      ImportDeclaration(node) {
        const moduleName = node.source?.value;
        if (typeof moduleName !== 'string') return;
        if (!BARREL_PATTERN.test(moduleName)) return;
        if (isTypeOnlyImport(node)) return;

        context.report({
          node,
          messageId: 'noValueImport',
          data: { module: moduleName },
        });
      },
    };
  },
};

export default {
  rules: {
    'no-generated-models-barrel-value-import': noGeneratedModelsBarrelValueImportRule,
  },
};
